mapper.select:
SELECT IB.POST_SN AS postSn, IB.POST_SJ AS title
FROM INSTRUCTOR_BOARD IB
      INNER JOIN INSTRUCTOR I ON IB.INSTR_USER_ID = I.INSTR_USER_ID
WHERE I.INSTR_UUID     = #{instrUuid}
  AND IB.BOARD_TYPE_CD = #{boardTypeCd}
  AND IB.CLASS_SN      IS NULL
  AND IB.USE_YN        = 'Y'
  AND IB.POST_SN       < #{postSn}
ORDER BY IB.POST_SN DESC
FETCH FIRST 1 ROWS ONLY

SELECT IB.POST_SN AS postSn, IB.POST_SJ AS title
FROM INSTRUCTOR_BOARD IB
      INNER JOIN INSTRUCTOR I ON IB.INSTR_USER_ID = I.INSTR_USER_ID
WHERE I.INSTR_UUID     = #{instrUuid}
  AND IB.BOARD_TYPE_CD = #{boardTypeCd}
  AND IB.CLASS_SN      IS NULL
  AND IB.USE_YN        = 'Y'
  AND IB.POST_SN       > #{postSn}
ORDER BY IB.POST_SN ASC
FETCH FIRST 1 ROWS ONLY

